   console.log(`Found ${projects.length} projects\n`);

+  // Clean stale project directories before regenerating
+  // Preserve: index.mdx (git-tracked stub, not regenerated by sync)
+  // Preserve: timeline/ (generated separately at end of sync)
+  const existingEntries = await fs.readdir(changelogContentDir, {
+    withFileTypes: true,
+  });
+  const validProjectIds = new Set(projects.map((p) => p.id));
+
+  for (const entry of existingEntries) {
+    // Skip non-directories (includes index.mdx stub file)
+    if (!entry.isDirectory()) {
+      continue;
+    }
+    // Skip timeline directory (regenerated separately later in sync)
+    if (entry.name === "timeline") {
+      continue;
+    }
+    // Remove project directories not in current news repo
+    if (!validProjectIds.has(entry.name)) {
+      const stalePath = path.join(changelogContentDir, entry.name);
+      console.log(`  Removing stale project: ${entry.name}`);
+      await fs.rm(stalePath, { recursive: true, force: true });
+    }
+  }
